import geraSenha from "./geradores";
const senhaGerada = document.querySelector('.senhas-gerada')
const qtd_caracteres = document.querySelector('.qtd-caracteres');
const chkMaiusculas = document.querySelector('.chk-maiusculas');
const chkMinusculas = document.querySelector('.chk-minusculas');
const chkNumeros = document.querySelector('.chk-numeros');
const chkSimbolos = document.querySelector('.chk-simbolos');
const gerarSenha = document.querySelector('.gerar-senha')

export default () => {
    gerarSenha.addEventListener('click', () => {
        senhaGerada.innerHTML = gera(   )
    })
}
''
function gera() {
    const senha = geraSenha(qtd_caracteres.value,
        chkMaiusculas.checked,
        chkMinusculas.checked,
        chkNumeros.checked,
        chkSimbolos.checked)

        return senha || "nada selecionado"; // se senha for false entao vai pro nada selecionado
}
